import os
import subprocess

def get_ls_result(dir_path: str) -> str:
    base_dir = "/home/user/"
    resolved_path = os.path.abspath(dir_path)
    if not resolved_path.startswith(base_dir) or not os.path.isdir(resolved_path):
        return ""
    try:
        result = subprocess.run(
            ['/bin/ls', '-l'],
            cwd=resolved_path,
            capture_output=True,
            text=True,
            check=True
        )
        return result.stdout
    except (subprocess.CalledProcessError, FileNotFoundError, OSError) as e:
        return ""
    except Exception as e:
        return ""
